import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { API } from '@/App';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { toast } from 'sonner';
import { ArrowLeft, Trash2, Plus, Minus } from 'lucide-react';

const CartPage = ({ user }) => {
  const navigate = useNavigate();
  const [cart, setCart] = useState({ items: [], restaurant_id: null });
  const [deliveryAddress, setDeliveryAddress] = useState(user?.address || '');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchCart();
  }, []);

  const fetchCart = async () => {
    try {
      const response = await axios.get(`${API}/cart`);
      setCart(response.data);
    } catch (error) {
      console.error('Error fetching cart:', error);
    }
  };

  const updateQuantity = async (menuItemId, quantity) => {
    try {
      await axios.put(`${API}/cart/update`, {
        menu_item_id: menuItemId,
        quantity
      });
      fetchCart();
      if (quantity === 0) {
        toast.success('Item removed from cart');
      }
    } catch (error) {
      toast.error('Failed to update cart');
    }
  };

  const clearCart = async () => {
    try {
      await axios.delete(`${API}/cart/clear`);
      setCart({ items: [], restaurant_id: null });
      toast.success('Cart cleared');
    } catch (error) {
      toast.error('Failed to clear cart');
    }
  };

  const placeOrder = async () => {
    if (!deliveryAddress.trim()) {
      toast.error('Please enter delivery address');
      return;
    }

    setLoading(true);
    try {
      await axios.post(`${API}/orders`, {
        delivery_address: deliveryAddress
      });
      toast.success('Order placed successfully!');
      navigate('/orders');
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Failed to place order');
    } finally {
      setLoading(false);
    }
  };

  const total = cart.items.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#FFF5EE] to-[#FFE4E1]">
      <div className="max-w-4xl mx-auto px-4 py-8">
        <div className="flex items-center gap-4 mb-8">
          <Button
            variant="ghost"
            onClick={() => navigate('/')}
            data-testid="back-to-home-btn"
          >
            <ArrowLeft className="w-5 h-5" />
          </Button>
          <h1 className="text-3xl font-bold text-gray-800">Your Cart</h1>
        </div>

        {cart.items.length === 0 ? (
          <div className="bg-white rounded-2xl shadow-md p-12 text-center">
            <p className="text-gray-500 text-lg mb-6" data-testid="empty-cart-msg">Your cart is empty</p>
            <Button
              onClick={() => navigate('/')}
              data-testid="browse-restaurants-btn"
              className="bg-[#FF6B6B] hover:bg-[#EE5A52] text-white"
            >
              Browse Restaurants
            </Button>
          </div>
        ) : (
          <div className="grid lg:grid-cols-3 gap-6">
            {/* Cart Items */}
            <div className="lg:col-span-2 space-y-4">
              <div className="bg-white rounded-2xl shadow-md p-6">
                <div className="flex justify-between items-center mb-4">
                  <h2 className="text-xl font-semibold">Items</h2>
                  <Button
                    variant="ghost"
                    onClick={clearCart}
                    data-testid="clear-cart-btn"
                    className="text-red-500 hover:text-red-600"
                  >
                    <Trash2 className="w-4 h-4 mr-2" />
                    Clear Cart
                  </Button>
                </div>
                <div className="space-y-4">
                  {cart.items.map((item) => (
                    <div
                      key={item.menu_item_id}
                      data-testid={`cart-item-${item.menu_item_id}`}
                      className="flex gap-4 p-3 hover:bg-gray-50 rounded-lg transition-colors"
                    >
                      <img
                        src={item.image}
                        alt={item.name}
                        className="w-20 h-20 object-cover rounded-lg"
                      />
                      <div className="flex-1">
                        <h3 className="font-semibold text-gray-800">{item.name}</h3>
                        <p className="text-[#FF6B6B] font-bold">${item.price.toFixed(2)}</p>
                        <div className="flex items-center gap-2 mt-2">
                          <button
                            onClick={() => updateQuantity(item.menu_item_id, item.quantity - 1)}
                            data-testid={`decrease-cart-qty-${item.menu_item_id}`}
                            className="p-1 hover:bg-gray-200 rounded-full"
                          >
                            <Minus className="w-4 h-4" />
                          </button>
                          <span className="w-8 text-center font-semibold" data-testid={`cart-qty-${item.menu_item_id}`}>
                            {item.quantity}
                          </span>
                          <button
                            onClick={() => updateQuantity(item.menu_item_id, item.quantity + 1)}
                            data-testid={`increase-cart-qty-${item.menu_item_id}`}
                            className="p-1 hover:bg-gray-200 rounded-full"
                          >
                            <Plus className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="font-bold text-gray-800">${(item.price * item.quantity).toFixed(2)}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Order Summary */}
            <div className="lg:col-span-1">
              <div className="bg-white rounded-2xl shadow-md p-6 sticky top-4">
                <h2 className="text-xl font-semibold mb-4">Order Summary</h2>

                <div className="space-y-3 mb-4">
                  <div className="flex justify-between text-gray-600">
                    <span>Subtotal</span>
                    <span data-testid="cart-subtotal">${total.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-gray-600">
                    <span>Delivery Fee</span>
                    <span>$2.99</span>
                  </div>
                  <div className="border-t pt-3">
                    <div className="flex justify-between font-bold text-lg">
                      <span>Total</span>
                      <span className="text-[#FF6B6B]" data-testid="cart-total">${(total + 2.99).toFixed(2)}</span>
                    </div>
                  </div>
                </div>

                <div className="mb-4">
                  <label className="block text-sm font-medium mb-2">Delivery Address</label>
                  <Input
                    type="text"
                    value={deliveryAddress}
                    onChange={(e) => setDeliveryAddress(e.target.value)}
                    data-testid="delivery-address-input"
                    placeholder="Enter your address"
                    className="w-full"
                  />
                </div>

                <Button
                  onClick={placeOrder}
                  disabled={loading || !deliveryAddress.trim()}
                  data-testid="place-order-btn"
                  className="w-full bg-[#FF6B6B] hover:bg-[#EE5A52] text-white py-6 rounded-full text-lg"
                >
                  {loading ? 'Placing Order...' : 'Place Order'}
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CartPage;
